// src/components/Navbar.jsx

export default function Navbar() {

  const logout = () => {

    localStorage.removeItem("user");

    window.location = "/";
  };

  return (

    <div style={styles.navbar}>

      <div style={styles.logoBox}>

        <h2 style={styles.logoText}>
          DailyMajdoor
        </h2>

      </div>

      <div style={styles.menu}>

        <button
          style={styles.homeBtn}
          onClick={() => window.location = "/"}
        >
          Home
        </button>

        <button
          style={styles.logoutBtn}
          onClick={logout}
        >
          Logout
        </button>

      </div>

    </div>
  );
}

const styles = {

  navbar: {
    height: "68px",
    background: "white",
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center",
    padding: "0 60px",
    borderBottom: "1px solid #eef2f7"
  },

  logoBox: {
    display: "flex",
    alignItems: "center"
  },

  logoText: {
    fontSize: "20px",
    color: "#111827",
    margin: 0
  },

  menu: {
    display: "flex",
    gap: "12px"
  },

  homeBtn: {
    background: "#f3f4f6",
    border: "none",
    padding: "10px 18px",
    borderRadius: "8px",
    cursor: "pointer"
  },

  logoutBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "10px 18px",
    borderRadius: "8px",
    cursor: "pointer"
  }

};
